#include <stdio.h>
#include <stdlib.h>

/*
 * REPRESENTING CHAINS IN C
 * ========================
 * A chain (singly linked list) consists of nodes where each node
 * contains data and a pointer to the next node.
 */

/* Self-referential structure - the foundation of chain representation */
/* The 'next' pointer stores the address of the next Node */
typedef struct Node {
 int data; /* Data field to store information */
 struct Node *next; /* Pointer to the next node in chain */
} Node;

/* Function prototypes */
Node* createNode(int value);
void displayChain(Node *head);
int countNodes(Node *head);
Node* search(Node *head, int key);
Node* insertAtBeginning(Node *head, int value);
Node* insertAtEnd(Node *head, int value);
Node* deleteNode(Node *head, int key);
void freeChain(Node *head);

/*
 * CREATE NODE FUNCTION
 * ====================
 * Allocates memory for a new node using malloc().
 * Returns pointer to the newly created node.
 */
Node* createNode(int value) {
 /* Step 1: Allocate memory for one node */
 Node *newNode = (Node *)malloc(sizeof(Node));

 /* Step 2: Always check if malloc failed (NULL check) */
 if (newNode == NULL) {
 printf("Error: Memory allocation failed!\n");
 exit(1); /* Exit with error code 1 */
 }

 /* Step 3: Initialize the data field */
 newNode->data = value;

 /* Step 4: Initialize next pointer to NULL (end of chain marker) */
 newNode->next = NULL;

 /* Step 5: Return the newly created node */
 return newNode;
}

/*
 * DISPLAY CHAIN FUNCTION
 * =====================
 * Traverses the chain and prints each node's data.
 * Pattern: Start at head, while not NULL, process and move to next.
 */
void displayChain(Node *head) {
 Node *current = head; /* 'current' tracks our position in chain */

 if (current == NULL) {
 printf("Chain is empty.\n");
 return;
 }

 /* Traverse: visit each node until we reach NULL */
 while (current != NULL) {
 printf("%d -> ", current->data);
 current = current->next; /* Move to next node */
 }
 printf("NULL\n");
}

/*
 * COUNT NODES FUNCTION
 * ===================
 * Counts the total number of nodes in the chain.
 * Time Complexity: O(n)
 */
int countNodes(Node *head) {
 int count = 0;
 Node *current = head;

 while (current != NULL) {
 count++;
 current = current->next;
 }

 return count;
}

/*
 * SEARCH FUNCTION
 * ===============
 * Searches for a value in the chain.
 * Returns pointer to node if found, NULL otherwise.
 * Time Complexity: O(n)
 */
Node* search(Node *head, int key) {
 Node *current = head;

 while (current != NULL) {
 if (current->data == key) {
 return current; /* Found! Return node pointer */
 }
 current = current->next;
 }

 return NULL; /* Not found */
}

/*
 * INSERT AT BEGINNING
 * ==================
 * Adds a new node at the start of the chain.
 * Time Complexity: O(1)
 * Returns the new head pointer (may change).
 */
Node* insertAtBeginning(Node *head, int value) {
 Node *newNode = createNode(value);

 newNode->next = head; /* Link new node to current head */
 head = newNode; /* Update head to new node */

 return head; /* Return new head */
}

/*
 * INSERT AT END
 * =============
 * Adds a new node at the end of the chain.
 * Time Complexity: O(n)
 * Returns the head pointer (unchanged unless empty).
 */
Node* insertAtEnd(Node *head, int value) {
 Node *newNode = createNode(value);

 /* If chain is empty, new node becomes head */
 if (head == NULL) {
 return newNode;
 }

 /* Traverse to the last node */
 Node *current = head;
 while (current->next != NULL) {
 current = current->next;
 }

 /* Link last node to new node */
 current->next = newNode;

 return head;
}

/*
 * DELETE NODE BY VALUE
 * ====================
 * Deletes the first node containing the specified value.
 * Time Complexity: O(n)
 * Returns the head pointer (may change).
 */
Node* deleteNode(Node *head, int key) {
 /* Case 1: Empty chain */
 if (head == NULL) {
 printf("Chain is empty.\n");
 return NULL;
 }

 /* Case 2: Head node contains the key */
 if (head->data == key) {
 Node *temp = head;
 head = head->next; /* Move head to next node */
 free(temp); /* Free old head memory */
 printf("Deleted %d from beginning.\n", key);
 return head;
 }

 /* Case 3: Search for node to delete */
 Node *current = head;
 while (current->next != NULL && current->next->data != key) {
 current = current->next;
 }

 /* Node found - delete it */
 if (current->next != NULL) {
 Node *temp = current->next;
 current->next = temp->next; /* Bypass the node */
 free(temp); /* Free memory */
 printf("Deleted %d.\n", key);
 } else {
 printf("Value %d not found in chain.\n", key);
 }

 return head;
}

/*
 * FREE CHAIN FUNCTION
 * ===================
 * Frees all nodes to prevent memory leaks.
 * Important: Save 'next' before calling free()!
 */
void freeChain(Node *head) {
 Node *current = head;

 while (current != NULL) {
 Node *nextNode = current->next; /* Save next before freeing! */
 free(current); /* Free current node */
 current = nextNode; /* Move to next node */
 }
 printf("Chain memory freed.\n");
}

/*
 * MAIN FUNCTION - Demonstration
 * =============================
 */
int main() {
 Node *head = NULL; /* Empty chain - head is NULL */

 printf("=== Representing Chains in C ===\n\n");

 /* Create nodes manually */
 printf("Creating nodes manually:\n");
 head = createNode(10); /* head -> 10 */
 head->next = createNode(20); /* head -> 10 -> 20 */
 head->next->next = createNode(30); /* head -> 10 -> 20 -> 30 */

 displayChain(head); /* Output: 10 -> 20 -> 30 -> NULL */

 /* Insert at beginning */
 printf("\nInserting 5 at beginning:\n");
 head = insertAtBeginning(head, 5);
 displayChain(head); /* Output: 5 -> 10 -> 20 -> 30 -> NULL */

 /* Insert at end */
 printf("\nInserting 40 at end:\n");
 head = insertAtEnd(head, 40);
 displayChain(head);

 /* Count nodes */
 printf("\nNode count: %d\n", countNodes(head));

 /* Search */
 printf("\nSearching for 20:\n");
 Node *found = search(head, 20);
 if (found != NULL) {
 printf("Found %d at address %p\n", found->data, (void*)found);
 }

 printf("\nSearching for 25:\n");
 found = search(head, 25);
 if (found == NULL) {
 printf("Value 25 not found.\n");
 }

 /* Delete */
 printf("\nDeleting 20:\n");
 head = deleteNode(head, 20);
 displayChain(head);

 /* Free all memory */
 freeChain(head);
 head = NULL; /* Good practice: set to NULL after freeing */

 return 0;
}
